import 'react-toastify/dist/ReactToastify.css';
import { db } from '../config/firebase';
import { getDocs, doc, getDoc } from 'firebase/firestore';
import React, { useState, useEffect } from 'react';
import Fuse from 'fuse.js';

export default function Table() {
  const [showChart, setChart] = useState(false);
  const [showTable, setTable] = useState(false);
  const [errorMessage, setErrorMessage] = useState('');
  const [cityPassword, setCityPassword] = useState('');
  const [cityName, setCityName] = useState('');

  async function startTest(e) {
    e.preventDefault();
    const formData = new FormData(e.target);
    const formProps = Object.fromEntries(formData);
    const { city_name, city_password } = formProps;

    // retrieve all the city names in the database
    const docRef = doc(db, 'City');
    const docSnap = await getDocs(docRef);

    // convert the list of city names in the database to an array of objects
    const cities = docSnap.docs.map((doc) => ({ name: doc.id }));

    // configure Fuse.js options
    const fuseOptions = {
      keys: ['name'],
      includeScore: true,
      threshold: 0.4,
      ignoreLocation: true,
    };

    // search for the closest match to the user's input using Fuse.js
    const fuse = new Fuse(cities, fuseOptions);
    const matches = fuse.search(city_name);

    // get the closest match from the list of matches
    const closestMatch = matches.length > 0 ? matches[0].item : null;

    // check if the closest match exists in the database and has a matching password
    const cityRef = doc(db, 'City', closestMatch?.name);
    const citySnap = await getDoc(cityRef);
    const passwordRef = doc(db, 'Password', city_password);
    const passwordSnap = await getDoc(passwordRef);

    if (citySnap.exists() && closestMatch?.name === city_name && passwordSnap.exists()) {
      setCityName(closestMatch.name);
      setCityPassword(city_password);
      setTable(true);
      setErrorMessage('');
      setChart(true);
    } else {
      setErrorMessage('Nous sommes désolés mais les statistiques de votre ville ne semblent pas accessibles.');
    }
  }

  async function read(login) {
    const docRef = doc(db, 'City', login);
    const docSnap = await getDoc(docRef);
    const idArray = [];
    const dataArray = [];

    if (docSnap.exists()) {
      const data = docSnap.data();
      const [cleanarray] = Object.values(data);

      for (const value of cleanarray) {
        const id = String(value);
        const count = idArray.push(id);
      }
    } else {
      console.log('No such document!');
    }

    for (const element of idArray) {
      const test = element;
      const docRef2 = doc(db, 'Routes', test);
      const docSnap2 = await getDoc(docRef2);
      const data2 = docSnap2.data();

      const datajson = JSON.stringify(data2, null, 2);
      const objx = JSON.parse(datajson);

      dataArray.push(objx);
    }

    return dataArray;
  }

  const Reader = ({ cname }) => {
    const [dataread, setData] = useState([]);
    const [loading, setLoading] = useState(true);
  
    async function getCities() {
      const docRef = doc(db, 'City');
      const docSnap = await getDocs(docRef);
  
      const cities = docSnap.docs.map((doc) => ({ name: doc.id }));
  
      const fuseOptions = {
        keys: ['name'],
        includeScore: true,
        threshold: 0.4,
        ignoreLocation: true,
      };
  
      const fuse = new Fuse(cities, fuseOptions);
      const matches = fuse.search(cname);
  
      const closestMatch = matches.length > 0 ? matches[0].item : null;
  
      return closestMatch?.name || '';
    }
  
    async function read(login) {
      const docRef = doc(db, 'City', login);
      const docSnap = await getDoc(docRef);
      const idArray = [];
      const dataArray = [];
  
      if (docSnap.exists()) {
        const data = docSnap.data();
        const [cleanarray] = Object.values(data);
  
        for (const value of cleanarray) {
          const id = String(value);
          const count = idArray.push(id);
        }
      } else {
        console.log('No such document!');
      }
  
      for (const element of idArray) {
        const test = element;
        const docRef2 = doc(db, 'Routes', test);
        const docSnap2 = await getDoc(docRef2);
        const data2 = docSnap2.data();
  
        const datajson = JSON.stringify(data2, null, 2);
        const objx = JSON.parse(datajson);
  
        dataArray.push(objx);
      }
  
      return dataArray;
    }
  
    useEffect(() => {
      async function fetchUserData() {
        setLoading(true);
        const closestMatch = await getCities();
        const response = await read(closestMatch);
        setData(response);
        setLoading(false);
      }
  
      if (cname) {
        fetchUserData();
      }
    }, [cname]);
  
    if (loading) return <p>Loading...</p>;
  
    return (
      <table>
        <thead>
          <tr>
            <th>ID </th>
            <th>City name </th>
            <th>Route name </th>
            <th>Number of sessions </th>
          </tr>
        </thead>
        <tbody>
          {dataread.map((item) => (
            <tr key={item.id}>
              <td>{item.id}</td>
              <td>{item.nameCity}</td>
              <td>{item.nameRoute}</td>
              <td>{item.nbrSessions}</td>
            </tr>
          ))}
        </tbody>
      </table>
    );
  };
}
